import re
from dataclasses import dataclass, field
from typing import List, Dict, Any, Optional, Tuple
from collections import defaultdict
import copy

# ==========================
# Custom Exceptions
# ==========================
class QueryError(Exception):
    """Base exception for query processing errors."""
    pass

class LexError(QueryError): pass
class ParseError(QueryError): pass
class ValidationError(QueryError): pass
class ExecutionError(QueryError): pass

# ==========================
# Token & AST Definitions
# ==========================
@dataclass
class Token:
    type: str
    value: str
    pos: int

@dataclass
class SelectItem:
    is_aggregate: bool = False
    func: Optional[str] = None
    column: Optional[str] = None
    is_wildcard: bool = False

@dataclass
class Condition:
    left: str
    op: str
    right: Any

@dataclass
class Join:
    table: str
    alias: Optional[str] = None
    on: Condition = None

@dataclass
class OrderBy:
    column: str
    asc: bool = True

@dataclass
class Query:
    select: List[SelectItem] = field(default_factory=list)
    from_table: Optional[str] = None
    from_alias: Optional[str] = None
    where: Optional[Condition] = None
    joins: List[Join] = field(default_factory=list)
    group_by: List[str] = field(default_factory=list)
    order_by: List[OrderBy] = field(default_factory=list)

# ==========================
# Lexer
# ==========================
KEYWORDS = {'SELECT', 'FROM', 'WHERE', 'JOIN', 'ON', 'GROUP', 'BY', 'ORDER', 'ASC', 'DESC', 'AS'}
AGGREGATES = {'COUNT', 'SUM', 'AVG', 'MIN', 'MAX'}
OPERATORS = {'=', '!=', '<', '>', '<=', '>='}

# Regex pattern for tokenization
TOKEN_PATTERN = re.compile(r"""
    (?P<KEYWORD>\b(?:SELECT|FROM|WHERE|JOIN|ON|GROUP|BY|ORDER|ASC|DESC|AS|COUNT|SUM|AVG|MIN|MAX)\b)
    |(?P<OPERATOR>(?:!=|<=|>=|<|>|=))
    |(?P<PUNCTUATION>[,()])
    |(?P<WILDCARD>\*)
    |(?P<IDENTIFIER>\b[a-zA-Z_]\w*(?:\.\w+)?\b)
    |(?P<NUMBER>\b\d+(?:\.\d+)?\b)
    |(?P<STRING>'[^']*')
    |(?P<SPACE>\s+)
""", re.VERBOSE)

def tokenize(query: str) -> List[Token]:
    tokens = []
    for match in TOKEN_PATTERN.finditer(query):
        kind = match.lastgroup
        value = match.group()
        if kind == 'SPACE':
            continue
        tokens.append(Token(type=kind, value=value.upper() if kind == 'KEYWORD' else value, pos=match.start()))
    return tokens

# ==========================
# Parser
# ==========================
class Parser:
    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> Optional[Token]:
        return self.tokens[self.pos] if self.pos < len(self.tokens) else None

    def consume(self, expected_type: str = None, expected_value: str = None) -> Token:
        token = self.peek()
        if token is None:
            raise ParseError(f"Unexpected end of query. Expected: {expected_value or expected_type}")
        if expected_type and token.type != expected_type:
            raise ParseError(f"Expected token type '{expected_type}', got '{token.type}' at position {token.pos}")
        if expected_value and token.value.upper() != expected_value.upper():
            raise ParseError(f"Expected '{expected_value}', got '{token.value}' at position {token.pos}")
        self.pos += 1
        return token

    def parse(self) -> Query:
        self.consume(expected_value='SELECT')
        query = Query()
        query.select = self._parse_select_list()
        self.consume(expected_value='FROM')
        query.from_table = self.consume().value
        if self.peek() and self.peek().value.upper() == 'AS':
            self.consume()
            query.from_alias = self.consume().value

        if self.peek() and self.peek().value.upper() == 'WHERE':
            self.consume()
            query.where = self._parse_condition()

        while self.peek() and self.peek().value.upper() == 'JOIN':
            self.consume()
            join_table = self.consume().value
            join_alias = None
            if self.peek() and self.peek().value.upper() == 'AS':
                self.consume()
                join_alias = self.consume().value
            self.consume(expected_value='ON')
            on_cond = self._parse_condition()
            query.joins.append(Join(table=join_table, alias=join_alias, on=on_cond))

        if self.peek() and self.peek().value.upper() == 'GROUP':
            self.consume()
            self.consume(expected_value='BY')
            query.group_by = self._parse_column_list()

        if self.peek() and self.peek().value.upper() == 'ORDER':
            self.consume()
            self.consume(expected_value='BY')
            query.order_by = self._parse_order_list()

        return query

    def _parse_select_list(self) -> List[SelectItem]:
        items = [self._parse_select_item()]
        while self.peek() and self.peek().type == 'PUNCTUATION' and self.peek().value == ',':
            self.consume()
            items.append(self._parse_select_item())
        return items

    def _parse_select_item(self) -> SelectItem:
        tok = self.peek()
        if tok.type == 'KEYWORD' and tok.value in AGGREGATES:
            func = self.consume().value
            self.consume(expected_type='PUNCTUATION', expected_value='(')
            arg = self.peek()
            if arg.type == 'WILDCARD':
                self.consume()
                self.consume(expected_type='PUNCTUATION', expected_value=')')
                return SelectItem(is_aggregate=True, func=func, is_wildcard=True)
            else:
                col = self.consume().value
                self.consume(expected_type='PUNCTUATION', expected_value=')')
                return SelectItem(is_aggregate=True, func=func, column=col)
        elif tok.type == 'WILDCARD':
            self.consume()
            return SelectItem(is_wildcard=True)
        else:
            return SelectItem(column=self.consume().value)

    def _parse_condition(self) -> Condition:
        left = self.consume().value
        op = self.consume().value
        right_tok = self.consume()
        right = right_tok.value
        if right_tok.type == 'NUMBER':
            right = float(right) if '.' in right else int(right)
        elif right_tok.type == 'STRING':
            right = right.strip("'")
        return Condition(left=left, op=op, right=right)

    def _parse_column_list(self) -> List[str]:
        cols = [self.consume().value]
        while self.peek() and self.peek().type == 'PUNCTUATION' and self.peek().value == ',':
            self.consume()
            cols.append(self.consume().value)
        return cols

    def _parse_order_list(self) -> List[OrderBy]:
        items = []
        col = self.consume().value
        asc = True
        if self.peek() and self.peek().value.upper() in ('ASC', 'DESC'):
            asc = self.consume().value.upper() == 'ASC'
        items.append(OrderBy(column=col, asc=asc))
        while self.peek() and self.peek().type == 'PUNCTUATION' and self.peek().value == ',':
            self.consume()
            col = self.consume().value
            asc = True
            if self.peek() and self.peek().value.upper() in ('ASC', 'DESC'):
                asc = self.consume().value.upper() == 'ASC'
            items.append(OrderBy(column=col, asc=asc))
        return items

# ==========================
# Validator
# ==========================
class Validator:
    def __init__(self, datasets: Dict[str, List[Dict]]):
        self.datasets = datasets

    def validate(self, query: Query) -> None:
        if query.from_table not in self.datasets:
            raise ValidationError(f"Unknown table: '{query.from_table}'")

        # Map aliases to actual table names
        alias_map = {query.from_table: query.from_table}
        if query.from_alias:
            alias_map[query.from_alias] = query.from_table

        for j in query.joins:
            if j.table not in self.datasets:
                raise ValidationError(f"Unknown table: '{j.table}'")
            alias_map[j.alias or j.table] = j.table

        # Validate columns in SELECT, WHERE, JOIN ON, GROUP BY, ORDER BY
        self._validate_ref(query.where, alias_map)
        for j in query.joins:
            self._validate_ref(j.on, alias_map)
        for col in query.group_by:
            self._validate_ref_col(col, alias_map)
        for o in query.order_by:
            self._validate_ref_col(o.column, alias_map)

        # Group-by consistency: non-aggregate select items must be in group_by
        if query.group_by:
            gb_cols = set(query.group_by)
            for s in query.select:
                if not s.is_aggregate and not s.is_wildcard and s.column not in gb_cols:
                    raise ValidationError(f"Column '{s.column}' must be in GROUP BY or aggregated")

    def _validate_ref(self, cond: Optional[Condition], alias_map: Dict[str, str]):
        if not cond: return
        self._validate_ref_col(cond.left, alias_map)
        if isinstance(cond.right, str):
            self._validate_ref_col(cond.right, alias_map)

    def _validate_ref_col(self, col: str, alias_map: Dict[str, str]):
        parts = col.split('.', 1)
        alias = parts[0] if len(parts) > 1 else None
        field = parts[-1]

        if alias:
            if alias not in alias_map:
                raise ValidationError(f"Unknown alias: '{alias}'")
            table = alias_map[alias]
        else:
            # Try to resolve unqualified column
            found = False
            for tbl in alias_map.values():
                if field in self.datasets[tbl][0]:
                    found = True
                    table = tbl
                    break
            if not found:
                raise ValidationError(f"Cannot resolve column: '{col}'")

        if field not in self.datasets[table]:
            raise ValidationError(f"Unknown column '{field}' in table '{table}'")

# ==========================
# Executor
# ==========================
class Executor:
    def __init__(self, datasets: Dict[str, List[Dict]]):
        self.datasets = datasets

    def execute(self, query: Query) -> List[Dict]:
        alias_map = {query.from_table: query.from_table}
        if query.from_alias:
            alias_map[query.from_alias] = query.from_table

        # Start with base table, normalize keys to table.field to avoid collisions
        current = [{f"{query.from_table}.{k}": v for k, v in row.items()} for row in self.datasets[query.from_table]]

        # 1. Filter (WHERE)
        if query.where:
            current = self._filter(current, query.where, alias_map)

        # 2. Join
        for j in query.joins:
            right_table = j.table
            right_alias = j.alias or right_table
            alias_map[right_alias] = right_table
            right_data = [{f"{right_table}.{k}": v for k, v in row.items()} for row in self.datasets[right_table]]
            current = self._join(current, right_data, j.on, alias_map)

        # 3. Group & Aggregate
        if query.group_by:
            current = self._group_by(current, query.select, query.group_by, alias_map)
        elif any(s.is_aggregate for s in query.select):
            current = self._global_aggregate(current, query.select, alias_map)

        # 4. Order By
        if query.order_by:
            current = self._order_by(current, query.order_by, alias_map)

        # 5. Project SELECT
        if not all(s.is_wildcard for s in query.select):
            current = self._project(current, query.select, alias_map)

        return current

    def _resolve(self, col_ref: str, record: Dict, alias_map: Dict[str, str]) -> Any:
        if '.' in col_ref:
            alias, field = col_ref.split('.', 1)
            table = alias_map.get(alias, alias)
            return record.get(f"{table}.{field}")
        return record.get(col_ref)

    def _filter(self, data: List[Dict], cond: Condition, alias_map: Dict[str, str]) -> List[Dict]:
        def eval_cond(rec):
            left = self._resolve(cond.left, rec, alias_map)
            right = self._resolve(cond.right, rec, alias_map) if isinstance(cond.right, str) else cond.right
            # Type coercion for safe comparison
            if isinstance(left, (int, float)) and isinstance(right, str):
                try: right = type(left)(right)
                except: return False
            if isinstance(left, str) and isinstance(right, (int, float)):
                try: left = type(right)(left)
                except: return False

            ops = {'=': left == right, '!=': left != right, '<': left < right,
                   '>': left > right, '<=': left <= right, '>=': left >= right}
            return ops.get(cond.op, False)
        return [r for r in data if eval_cond(r)]

    def _join(self, left: List[Dict], right: List[Dict], cond: Condition, alias_map: Dict[str, str]) -> List[Dict]:
        result = []
        for l_rec in left:
            for r_rec in right:
                merged = {**l_rec, **r_rec}
                l_val = self._resolve(cond.left, merged, alias_map)
                r_val = self._resolve(cond.right, merged, alias_map) if isinstance(cond.right, str) else cond.right
                if l_val == r_val:
                    result.append(merged)
        return result

    def _group_by(self, data: List[Dict], select: List[SelectItem], group_cols: List[str], alias_map: Dict[str, str]) -> List[Dict]:
        groups = defaultdict(list)
        for rec in data:
            key = tuple(self._resolve(c, rec, alias_map) for c in group_cols)
            groups[key].append(rec)

        result = []
        for key, group_records in groups.items():
            row = {}
            # Set group by values
            for c, val in zip(group_cols, key):
                row[c] = val

            # Compute aggregates
            for s in select:
                if s.is_aggregate:
                    vals = [self._resolve(s.column, r, alias_map) for r in group_records if s.column]
                    if s.func == 'COUNT' and s.is_wildcard:
                        row[s.func] = len(group_records)
                    else:
                        nums = [v for v in vals if v is not None and isinstance(v, (int, float))]
                        if not nums: nums = vals
                        if s.func == 'COUNT': row[f"{s.func}"] = len(nums)
                        elif s.func == 'SUM': row[f"{s.func}"] = sum(nums)
                        elif s.func == 'AVG': row[f"{s.func}"] = sum(nums) / len(nums) if nums else 0
                        elif s.func == 'MIN': row[f"{s.func}"] = min(nums) if nums else None
                        elif s.func == 'MAX': row[f"{s.func}"] = max(nums) if nums else None
                elif not s.is_wildcard:
                    row[s.column] = key[group_cols.index(s.column)] if s.column in group_cols else None
            result.append(row)
        return result

    def _global_aggregate(self, data: List[Dict], select: List[SelectItem], alias_map: Dict[str, str]) -> List[Dict]:
        row = {}
        for s in select:
            if s.is_aggregate:
                vals = [self._resolve(s.column, r, alias_map) for r in data if s.column]
                if s.func == 'COUNT' and s.is_wildcard:
                    row[s.func] = len(data)
                else:
                    nums = [v for v in vals if v is not None and isinstance(v, (int, float))]
                    if not nums: nums = vals
                    if s.func == 'COUNT': row[f"{s.func}"] = len(nums)
                    elif s.func == 'SUM': row[f"{s.func}"] = sum(nums)
                    elif s.func == 'AVG': row[f"{s.func}"] = sum(nums) / len(nums) if nums else 0
                    elif s.func == 'MIN': row[f"{s.func}"] = min(nums) if nums else None
                    elif s.func == 'MAX': row[f"{s.func}"] = max(nums) if nums else None
            else:
                row[s.column] = None
        return [row]

    def _order_by(self, data: List[Dict], order_specs: List[OrderBy], alias_map: Dict[str, str]) -> List[Dict]:
        def sort_key(rec):
            keys = []
            for spec in order_specs:
                val = self._resolve(spec.column, rec, alias_map)
                # Handle None in sorting
                if val is None: val = "" if isinstance(rec.get(spec.column), str) else float('inf')
                keys.append(val)
            return keys
        return sorted(data, key=sort_key, reverse=any(not s.asc for s in order_specs))

    def _project(self, data: List[Dict], select: List[SelectItem], alias_map: Dict[str, str]) -> List[Dict]:
        result = []
        for rec in data:
            row = {}
            for s in select:
                if s.is_aggregate:
                    row[s.func] = rec.get(s.func)
                elif s.is_wildcard:
                    row.update(rec)
                else:
                    row[s.column] = self._resolve(s.column, rec, alias_map)
            result.append(row)
        return result

# ==========================
# Query Engine Facade
# ==========================
class QueryEngine:
    def __init__(self, datasets: Dict[str, List[Dict]]):
        self.datasets = datasets
        self.validator = Validator(datasets)
        self.executor = Executor(datasets)

    def run(self, query_str: str) -> List[Dict]:
        try:
            tokens = tokenize(query_str)
            parser = Parser(tokens)
            ast = parser.parse()
            self.validator.validate(ast)
            return self.executor.execute(ast)
        except QueryError as e:
            raise e
        except Exception as e:
            raise ExecutionError(f"Unexpected execution failure: {e}") from e

# ==========================
# Example Usage
# ==========================
if __name__ == "__main__":
    # Sample datasets
    users = [
        {"id": 1, "name": "Alice", "department": "Engineering", "age": 29},
        {"id": 2, "name": "Bob", "department": "Sales", "age": 34},
        {"id": 3, "name": "Charlie", "department": "Engineering", "age": 27},
        {"id": 4, "name": "Diana", "department": "HR", "age": 31},
    ]
    orders = [
        {"order_id": 101, "user_id": 1, "total": 250.50},
        {"order_id": 102, "user_id": 1, "total": 120.00},
        {"order_id": 103, "user_id": 2, "total": 450.00},
        {"order_id": 104, "user_id": 3, "total": 89.99},
    ]

    db = QueryEngine(datasets={"users": users, "orders": orders})

    queries = [
        # 1. Basic filtering
        "SELECT name, age FROM users WHERE age > 28",
        # 2. Aggregation with GROUP BY
        "SELECT department, COUNT(*) FROM users GROUP BY department",
        # 3. Join + Filter + Aggregation
        "SELECT u.name, SUM(o.total) FROM users u JOIN orders o ON u.id = o.user_id GROUP BY u.name",
        # 4. Ordering
        "SELECT name, age FROM users ORDER BY age DESC",
        # 5. Invalid query (for error handling demo)
        # "SELECT salary FROM users WHERE id = 1"
    ]

    for i, q in enumerate(queries, 1):
        print(f"\n--- Query {i} ---")
        print(f"SQL: {q}")
        try:
            result = db.run(q)
            print("Result:")
            for row in result:
                print(row)
        except QueryError as e:
            print(f"Error: {e}")
