from typing import Dict, List, Any
import re

class QueryParser:
    def __init__(self):
        self.keywords = {
            'SELECT': {'type': 'select', 'args': ['*']},
            'FROM': {'type': 'from'},
            'WHERE': {'type': 'where'},
            'GROUP_BY': {'type': 'group_by'},
            'HAVING': {'type': 'having'},
            'ORDER_BY': {'type': 'order_by'},
            'JOIN': {'type': 'join'}
        }

    def parse(self, query: str) -> Dict[str, Any]:
        """
        Parse a query string into a structured format
        """
        try:
            # Split the query into tokens and remove whitespace
            tokens = re.findall(r'\w+|".*?("|$)|\(|\)', query.upper())

            parsed_query = {
                'select': [],
                'from': [],
                'where': {},
                'group_by': None,
                'having': None,
                'order_by': None,
                'join': []
            }

            current_clause = ''
            i = 0
            while i < len(tokens):
                token = tokens[i]

                if token in self.keywords:
                    current_clause = self.keywords[token]['type']

                    # Handle special cases
                    if current_clause == 'select':
                        # Get all columns until FROM or JOIN is found
                        next_token_index = i + 1
                        while (next_token_index < len(tokens) and 
                               tokens[next_token_index] not in ['FROM', 'JOIN']):
                            parsed_query['select'].append(tokens[next_token_index])
                            next_token_index += 1

                elif current_clause == '':
                    raise ValueError(f"Invalid token: {token} at position {i}")

                elif current_clause == 'where':
                    self._parse_where_condition(tokens[i:], parsed_query)

                elif current_clause == 'order_by':
                    # Handle ORDER BY clause
                    if i + 1 < len(tokens) and tokens[i+1] in ['ASC', 'DESC']:
                        parsed_query['order_by'] = {'column': tokens[i], 
                                                   'direction': tokens[i+1]}
                    else:
                        parsed_query['order_by'] = {'column': tokens[i], 
                                                   'direction': 'ASC'}

                elif current_clause == 'join':
                    # Handle JOIN clause
                    join_type = tokens[i + 1]
                    table_name = tokens[i + 3]
                    on_condition = {
                        'left_column': tokens[i + 4],
                        'operator': tokens[i + 5],
                        'right_column': tokens[i + 6]
                    }
                    parsed_query['join'].append({
                        'type': join_type,
                        'table': table_name,
                        'condition': on_condition
                    })

                i += 1

            return self._validate(parsed_query)

        except Exception as e:
            raise ValueError(f"Error parsing query: {str(e)}")

    def _parse_where_condition(self, tokens: List[str], parsed_query: Dict) -> None:
        """
        Parse WHERE clause conditions
        """
        i = 1
        while i < len(tokens):
            if tokens[i] in ['AND', 'OR']:
                condition_type = tokens[i]
                operator = tokens[i + 2]

                if tokens[i - 1] not in parsed_query['where']:
                    parsed_query['where'][tokens[i - 1]] = []

                parsed_query['where'][tokens[i - 1]].append({
                    'type': condition_type,
                    'operator': operator,
                    'value': tokens[i + 3]
                })
            i += 4

    def _validate(self, query: Dict) -> Dict:
        """
        Validate the parsed query
        """
        # Basic validation rules
        if not query['from']:
            raise ValueError("FROM clause is required")

        return query

class QueryExecutor:
    @staticmethod
    def execute(query: Dict[str, Any], data_sources: Dict[str, List[Dict]]) -> List[Dict]:
        """
        Execute the parsed query against provided data sources
        """
        # Simplified execution logic (would need to be more complex for real use)

        try:
            from_data = data_sources.get(query['from'][0])

            if not from_data:
                raise ValueError(f"Table {query['from'][0]} does not exist")

            result = from_data

            # Apply WHERE clause
            if query['where']:
                result = QueryExecutor._apply_where(result, query['where'])

            return result

        except Exception as e:
            raise RuntimeError(f"Error executing query: {str(e)}")

    @staticmethod
    def _apply_where(data: List[Dict], conditions: Dict) -> List[Dict]:
        """
        Apply WHERE conditions to data
        """
        filtered_data = []

        for row in data:
