            for column, condition_list in conditions.items():
                if not QueryExecutor._check_condition(row[column], condition_list):
                    matches_all_conditions = False
                    break

            if matches_all_conditions:
                filtered_data.append(row)

        return filtered_data

    @staticmethod
    def _check_condition(value: Any, conditions: List[Dict]) -> bool:
        """
        Check if a value meets the given conditions
        """
        for condition in conditions:
            operator = condition['operator']

            if operator == '=':
                if str(value) != str(condition['value']):
                    return False

        return True

